    function getConfigStorage_ACU() {
        const ns = USE_TAVERN_SETTINGS_STORAGE_ACU ? getTavernSettingsNamespace_ACU() : null;
        const hasTavern = !!ns;
        return {
            getItem: (key) => {
                if (hasTavern && Object.prototype.hasOwnProperty.call(ns, key))
                    return ns[key];
                const cached = configIdbGetCached_ACU(key);
                if (cached !== null && typeof cached !== 'undefined')
                    return cached;
                if (!FORBID_BROWSER_LOCAL_STORAGE_FOR_CONFIG_ACU && storage_ACU?.getItem)
                    return storage_ACU.getItem(key);
                return null;
            },
            setItem: (key, value) => {
                const v = String(value);
                if (hasTavern) {
                    ns[key] = v;
                    persistTavernSettings_ACU();
                }
                else if (!FORBID_BROWSER_LOCAL_STORAGE_FOR_CONFIG_ACU && storage_ACU?.setItem) {
                    storage_ACU.setItem(key, v);
                }
                void configIdbSetCached_ACU(key, v);
            },
            removeItem: (key) => {
                if (hasTavern) {
                    delete ns[key];
                    persistTavernSettings_ACU();
                }
                else if (!FORBID_BROWSER_LOCAL_STORAGE_FOR_CONFIG_ACU && storage_ACU?.removeItem) {
                    storage_ACU.removeItem(key);
                }
                void configIdbRemoveCached_ACU(key);
            },
            _isTavern: hasTavern,
        };
    }
    function migrateKeyToTavernStorageIfNeeded_ACU(key) {
        const store = getConfigStorage_ACU();
        if (!store || !store._isTavern)
            return false;
        const cur = store.getItem(key);
        if (cur !== null && typeof cur !== 'undefined')
            return false;
        if (!ALLOW_LEGACY_LOCALSTORAGE_MIGRATION_ACU || !legacyLocalStorage_ACU)
            return false;
        const legacy = legacyLocalStorage_ACU.getItem(key);
        if (legacy !== null && typeof legacy !== 'undefined') {
            store.setItem(key, legacy);
            try {
                legacyLocalStorage_ACU.removeItem(key);
            }
            catch (e) { /* ignore */ }
            return true;
        }
        return false;
    }
    function _set_pendingSettingsReloadFromIdb_ACU(v) { pendingSettingsReloadFromIdb_ACU = v; }
