        // Kiểm tra đồng bộ + Thêm bảng Tóm tắt/Đại cương
        let summaryInsertCount = 0;
        let outlineInsertCount = 0;
        const standardizedFillEnabled = settings_ACU?.standardizedTableFillEnabled !== false;
