            currentTemplatePresetName: '', // [Thiết lập sẵn Mẫu] Tên Thiết lập sẵn Mẫu hiện tại, trống biểu thị thiết lập sẵn mặc định
            // [Chức năng điền bảng] Trích xuất nhãn nội dung chính, trích xuất nội dung của nhãn được chỉ định từ Ngữ cảnh gửi cho AI, phản hồi User không bị ảnh hưởng
            tableContextExtractTags: '',
            tableContextExtractRules: [],
            // [Chức năng điền bảng] Loại trừ nhãn nội dung chính: loại bỏ nội dung nhãn được chỉ định khỏi Ngữ cảnh
            tableContextExcludeTags: '',
            tableContextExcludeRules: [],
