    // activePlotEditorSettings_ACU, currentPlotTaskEditorId_ACU, currentEditablePlotPresetState_ACU  đã 搬 đến  service/plot/plot-state.ts
    let plotTaskEditorAutoSaveTimer_ACU = null;
