    /**
     * Lấy cấu hình API theo tên thiết lập sẵn
     * @param {string} presetName - Tên thiết lập sẵn, chuỗi rỗng biểu thị sử dụng cấu hình hiện tại
     * @returns {object} - Đối tượng cấu hình bao gồm apiMode, apiConfig, tavernProfile
     */

    /**
     * presentation/triggers/settings-ui-sync/settings-ui-config.ts
     */
    function saveCustomCharCardPrompt_ACU() {
        if (!$popupInstance_ACU || !$charCardPromptSegmentsContainer_ACU) {
            logError_ACU('Lưu Cập nhật Cài đặt sẵn thất bại: Chưa khởi tạo thành phần UI.');
            return;
        }
        let newPromptSegments = getCharCardPromptFromUI_ACU();
        if (!newPromptSegments || newPromptSegments.length === 0 || (newPromptSegments.length === 1 && !newPromptSegments[0].content.trim())) {
            showToastr_ACU('warning', 'Cập nhật Cài đặt sẵn không được để trống.');
            return;
        }
        // [Tính toàn vẹn] Khử trùng lặp vị trí Prompt Chính: A/B mỗi cái tối đa 1 (phần dư sẽ tự động hạ cấp thành đoạn thường)
        try {
            const seen = { A: false, B: false };
            newPromptSegments = newPromptSegments.map(seg => {
                const slot = String(seg?.mainSlot || (seg?.isMain ? 'A' : (seg?.isMain2 ? 'B' : ''))).toUpperCase();
                if (slot === 'A' || slot === 'B') {
                    if (seen[slot]) {
                        const cleaned = { ...seg };
                        delete cleaned.mainSlot;
                        delete cleaned.isMain;
                        delete cleaned.isMain2;
                        cleaned.deletable = cleaned.deletable !== false;
                        return cleaned;
                    }
                    seen[slot] = true;
                }
                return seg;
            });
        }
        catch (e) { }
        // Lưu dưới dạng mảng JSON
        settings_ACU.charCardPrompt = newPromptSegments;
        saveSettingsAndNotify_ACU();
        showToastr_ACU('success', 'Đã lưu Cập nhật Cài đặt sẵn!');
        loadSettingsAndRefreshUI_ACU(); // This will re-render from the saved data.
    }
    function resetDefaultCharCardPrompt_ACU() {
        settings_ACU.charCardPrompt = isSqliteMode() ? DEFAULT_CHAR_CARD_PROMPT_SQL_ACU : DEFAULT_CHAR_CARD_PROMPT_ACU;
        saveSettingsAndNotify_ACU();
        showToastr_ACU('info', 'Cập nhật Cài đặt sẵn đã được khôi phục về giá trị mặc định!');
        // loadSettings will trigger renderPromptSegments_ACU which correctly handles the string default
        loadSettingsAndRefreshUI_ACU();
    }
    /**
     * Khôi phục Prompt điền bảng mặc định (charCardPrompt) theo chế độ đích được chỉ định.
     * Khác với resetDefaultCharCardPrompt_ACU, hàm này nhận tham số mode rõ ràng,
     * dùng cho trường hợp "Khôi phục Prompt mặc định của chế độ đích sau khi chuyển đổi chế độ" — khi đó chế độ hiện tại có thể chưa hoàn tất chuyển đổi.
     */
    function applyModeDefaultCharCardPrompt_ACU(mode) {
        settings_ACU.charCardPrompt = mode === 'sqlite' ? DEFAULT_CHAR_CARD_PROMPT_SQL_ACU : DEFAULT_CHAR_CARD_PROMPT_ACU;
        saveSettingsAndNotify_ACU();
        loadSettingsAndRefreshUI_ACU();
    }
    function loadCharCardPromptFromJson_ACU() {
        const input = document.createElement('input');
        input.type = 'file';
        input.accept = '.json';
        input.onchange = e => {
            const file = e.target.files[0];
            if (!file)
                return;
            const reader = new FileReader();
            reader.onload = readerEvent => {
                const content = readerEvent.target.result;
                let jsonData;
                try {
                    jsonData = JSON.parse(content);
                }
                catch (error) {
                    logError_ACU('Nhập Mẫu Prompt thất bại: Lỗi phân tích JSON.', error);
                    showToastr_ACU('error', 'Tệp không có định dạng JSON hợp lệ.', { timeOut: 5000 });
                    return;
                }
                try {
                    // Basic validation: must be an array of objects with role and content
                    if (!Array.isArray(jsonData) || jsonData.some(item => typeof item.role === 'undefined' || typeof item.content === 'undefined')) {
                        throw new Error('Định dạng JSON không chính xác. Yêu cầu phải là một mảng các đối tượng chứa khóa "role" và "content".');
                    }
                    // Add deletable: true and normalize roles for consistency
                    const segments = jsonData.map(item => {
                        let normalizedRole = 'USER'; // Default to USER
                        if (item.role) {
                            const roleLower = item.role.toLowerCase();
                            if (roleLower === 'system') {
                                normalizedRole = 'SYSTEM';
                            }
                            else if (roleLower === 'assistant' || roleLower === 'ai') {
                                normalizedRole = 'assistant';
                            }
                        }
                        const slot = String(item?.mainSlot || (item?.isMain ? 'A' : (item?.isMain2 ? 'B' : ''))).toUpperCase();
                        const normalizedSlot = (slot === 'A' || slot === 'B') ? slot : '';
                        return {
                            ...item,
                            role: normalizedRole,
                            mainSlot: normalizedSlot || item.mainSlot,
                            // Prompt Chính A/B không thể xóa
                            deletable: (normalizedSlot ? false : (item.deletable !== false)),
                        };
                    });
                    // Use the existing render function
                    renderPromptSegments_ACU(segments);
                    showToastr_ACU('success', 'Mẫu Prompt đã tải thành công!');
                    logDebug_ACU('New prompt template loaded from JSON file.');
                }
                catch (error) {
                    logError_ACU('Nhập Mẫu Prompt thất bại: Xác minh cấu trúc thất bại.', error);
                    showToastr_ACU('error', `Nhập thất bại: ${error.message}`, { timeOut: 10000 });
                }
            };
            reader.readAsText(file, 'UTF-8');
        };
        input.click();
    }
    // [+ Thêm] Xuất "Nhóm Prompt điền bảng (Cập nhật Cài đặt sẵn/AI chỉ thị Cài đặt sẵn)" thành JSON (kết hợp với loadCharCardPromptFromJson_ACU)
    function exportCharCardPromptToJson_ACU() {
        try {
            const segments = getCharCardPromptFromUI_ACU();
            if (!Array.isArray(segments) || segments.length === 0) {
                showToastr_ACU('warning', 'Không có Mẫu Prompt nào để xuất.');
                return;
            }
            // Xác minh cơ bản: phải bao gồm role/content
            const invalid = segments.some(s => !s || typeof s !== 'object' || typeof s.role === 'undefined' || typeof s.content === 'undefined');
            if (invalid) {
                showToastr_ACU('error', 'Xuất thất bại: Cấu trúc Prompt không hoàn chỉnh (thiếu role hoặc content).');
                return;
            }
            const jsonString = JSON.stringify(segments, null, 2);
            const blob = new Blob([jsonString], { type: 'application/json' });
            const url = URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.href = url;
            a.download = 'TavernDB_TablePromptGroup.json';
            document.body.appendChild(a);
            a.click();
            document.body.removeChild(a);
            URL.revokeObjectURL(url);
            showToastr_ACU('success', 'Đã xuất Mẫu Prompt thành JSON!', { acuToastCategory: ACU_TOAST_CATEGORY_ACU.MANUAL_TABLE });
        }
        catch (e) {
            logError_ACU('Xuất Mẫu Prompt thất bại:', e);
            showToastr_ACU('error', 'Xuất Mẫu Prompt thất bại, vui lòng kiểm tra bảng điều khiển để biết chi tiết.', { acuToastCategory: ACU_TOAST_CATEGORY_ACU.ERROR });
        }
    }
