    async function reoptimizeMessage_ACU(messageIndex) {
        const config = settings_ACU.contentOptimizationSettings || {};
        _set_contentOptimizationAbortRequested_ACU(false);
        // kiểm traCóKhôngBật
        if (!config.enabled) {
            showToastr_ACU('warning', 'Tối ưu nội dungChức năng chưa Bật');
            return false;
        }
        const chat = getChatArray_ACU();
        if (!chat || !chat[messageIndex]) {
            showToastr_ACU('error', 'Tin nhắnKhông tồn tại');
            return false;
        }
        const message = chat[messageIndex];
        // bỏ quaNgười dùngTin nhắn
        if (message.is_user) {
            showToastr_ACU('warning', 'Không thể tối ưu tin nhắn người dùng');
            return false;
        }
        // lấygốcNội dung
        const originalContent = getOriginalContent_ACU(messageIndex) || message.mes;
        if (!originalContent) {
            showToastr_ACU('error', 'Không thể lấy nội dung tin nhắn');
            return false;
        }
        logDebug_ACU(`[Tối ưu lại] Bắt đầu tối ưu lại tin nhắn ${messageIndex}, độ dài nội dung: ${originalContent.length}`);
        if (config.seamlessMode) {
            showOptimizationOverlay_ACU('Đang tối ưu lại nội dung chính...');
        }
        else {
            showOptimizationProgressToast_ACU('Đang tiến hành tối ưu nội dung (tối ưu lại)...');
        }
        try {
            ensureOptimizationNotCancelled_ACU();
            const result = await performContentOptimization_ACU(originalContent, {
                currentLoop: 1,
                userMessage: ''
            });
            hideOptimizationOverlay_ACU();
            hideOptimizationProgressToast_ACU();
            if (contentOptimizationAbortRequested_ACU) {
                return false;
            }
            if (!result.success) {
                showToastr_ACU('error', `lạiTối ưuThất bại: ${result.error || 'Lỗi không xác định'}`);
                return false;
            }
            if (!result.optimizations || result.optimizations.length === 0) {
                showToastr_ACU('info', 'Văn bản gốc đã đủ tốt, không cần tối ưu');
                return true;
            }
            showReoptimizationDialog_ACU(messageIndex, result, originalContent);
            return true;
        }
        catch (error) {
            hideOptimizationOverlay_ACU();
            hideOptimizationProgressToast_ACU();
            if (contentOptimizationAbortRequested_ACU || error?.message === 'Người dùng đã dừng tối ưu nội dung') {
                logDebug_ACU('[lạiTối ưu] Người dùngĐã hủyTối ưu nội dung');
                return false;
            }
            logError_ACU('[Tối ưu lại] Lỗi thực thi:', error);
            showToastr_ACU('error', `lạiTối ưuThất bại: ${error.message}`);
            return false;
        }
        finally {
            hideOptimizationOverlay_ACU();
            hideOptimizationProgressToast_ACU();
            _set_contentOptimizationAbortRequested_ACU(false);
        }
    }
