                        if (comment.startsWith('TavernDB-ACU-') || comment.startsWith('Tải lại mục nhân vật') || comment.startsWith('Mục tóm tắt')) {
                            return false;
                        }
                        // [+ Thêm] Lọc屏蔽từMục
                        if (isEntryBlocked_ACU(entry)) {
                            return false;
                        }
                        return true;
