                                    <button id="${SCRIPT_ID_PREFIX_ACU}-optimization-delete-preset" class="acu-btn-icon" title="Xóa cài đặt sẵn hiện tại đã chọn" style="display: none; color: var(--acu-danger);"><i class="fa-solid fa-trash-alt"></i></button>
